    private static bool[][] _grid;

    /// <summary>Grille 128x128 : grid[row][col], row 0 en haut. true = allume.</summary>
    public static bool[][] Grid()
    {
        if (_grid != null) return _grid;
        _grid = new bool[Size][];
        for (int y = 0; y < Size; y++)
        {
            _grid[y] = new bool[Size];
            string line = Rows[y];
            for (int x = 0; x < Size && x < line.Length; x++)
                _grid[y][x] = line[x] == '#';
        }
        return _grid;
    }
